spec: game-design.md
spec_version: 0.2.0-alpha
file_type: content-entity
id: fault_lines_07_the_chasm
status: draft
implemented_in: ["src/embergrave/levels/fault_lines_07_the_chasm.py"]
name: "The Chasm"
region: fault_lines
difficulty_tier: 3
time_target_ms: 180000
entry: { x: 1500, y: 17500 }
exit:  { x: 7500, y: 500 }
checkpoints:
